class LFUCache {
    private Map<Integer, Integer> keyValue;
    private Map<Integer, Integer> valueFrequency;
    private Map<Integer, LinkedList<Integer>> frequencyKeys;
    private int capacity;
    private int minFrequency;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        keyValue = new HashMap<>();
        valueFrequency = new HashMap<>();
        frequencyKeys = new HashMap<>();
        minFrequency = 0;
    }

    public int get(int key) {
        if (!keyValue.containsKey(key)) {
            return -1;
        }
        int value = keyValue.get(key);
        updateFrequency(key);
        return value;
    }

    public void put(int key, int value) {
        if (keyValue.containsKey(key)) {
            keyValue.put(key, value);
            updateFrequency(key);
        } else {
            if (keyValue.size() == capacity) {
                removeLeastFrequentKey();
            }
            keyValue.put(key, value);
            valueFrequency.put(key, 1);
            frequencyKeys.computeIfAbsent(1, k -> new LinkedList<>()).add(key);
            minFrequency = 1;
        }
    }

    private void updateFrequency(int key) {
        int frequency = valueFrequency.get(key);
        frequencyKeys.get(frequency).remove(Integer.valueOf(key));
        valueFrequency.put(key, frequency + 1);
        frequencyKeys.computeIfAbsent(frequency + 1, k -> new LinkedList<>()).add(key);
        if (frequencyKeys.get(minFrequency).isEmpty()) {
            minFrequency++;
        }
    }

    private void removeLeastFrequentKey() {
        int keyToRemove = frequencyKeys.get(minFrequency).removeFirst();
        keyValue.remove(keyToRemove);
        valueFrequency.remove(keyToRemove);
    }
}
